-- Patchnote 0.7.8 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.7.8', 'minor', '2026-05-03T00:00:00.000Z',
  'Account modal redesign, Jackett indexer + qBittorrent plugin contract',
  'Refonte du modal Compte, indexer Jackett + contrat plugin qBittorrent',
  '[{"type":"feat","titleEn":"Discord-like account modal with plugin sections","titleFr":"Modal Compte Discord-like avec sections plugin","descEn":"The avatar dropdown is replaced by a full-screen `AccountModal` with a sidebar (avatar header → section list → logout) and a content pane that swaps between built-in sections (Account, Preferences) and plugin-contributed ones via the new `account.section` hook point. Plugins declare an icon, label and React component; built-ins and plugin entries merge in a single sorted list.","descFr":"Le dropdown avatar est remplacé par un `AccountModal` plein écran avec une sidebar (header avatar → liste des sections → logout) et un panneau qui swap entre les sections built-in (Compte, Préférences) et celles contribuées par les plugins via le nouveau hook `account.section`. Les plugins déclarent une icône, un label et un composant React ; built-in et plugin se mélangent dans une liste unique triée par order."},{"type":"feat","titleEn":"User-selectable avatar source","titleFr":"Source d''avatar choisie par l''utilisateur","descEn":"#169 — pick which connected provider (Plex, Jellyfin, Emby, …) supplies your avatar. The new AvatarEditor surfaces every provider image you''re linked to and lets you swap on the fly without touching the file system.","descFr":"#169 — choisis quel provider connecté (Plex, Jellyfin, Emby, …) fournit ton avatar. Le nouvel AvatarEditor affiche chaque image de provider lié et te laisse swap à la volée sans toucher au filesystem."},{"type":"feat","titleEn":"Admin-defined custom topbar links","titleFr":"Liens topbar custom définis par l''admin","descEn":"#167 — admins can publish arbitrary URL shortcuts to the home topbar (label, icon, URL, target). Useful for pinning Tautulli, Overseerr, your dashboard, or any service users should reach in one click — without writing a plugin.","descFr":"#167 — les admins peuvent publier des raccourcis URL arbitraires dans la topbar (label, icône, URL, target). Pratique pour épingler Tautulli, Overseerr, ton dashboard, ou n''importe quel service à atteindre en un click — sans écrire de plugin."},{"type":"feat","titleEn":"Admin jump button + tooltip system","titleFr":"Bouton d''accès admin + système de tooltip","descEn":"A discreet shield/home button now sits in every topbar (admin gated) for one-click jumps between the user app and the admin panel — replacing the slower path through the avatar dropdown. Backed by a new shared Tooltip component with a 100ms fade (vs the browser''s ~1.5s native delay), reused on the avatar cog and the notification bell.","descFr":"Un discret bouton bouclier/maison habite maintenant chaque topbar (gated admin) pour switcher en un click entre l''app user et le panel admin — plus rapide que de passer par le dropdown avatar. Adossé à un nouveau composant Tooltip partagé avec un fade en 100ms (vs ~1.5s du natif navigateur), réutilisé sur le cog avatar et la cloche de notif."},{"type":"feat","titleEn":"Jackett indexer connector","titleFr":"Connecteur indexer Jackett","descEn":"New ''indexer'' service category with Jackett as its first member. The connection test uses the public-with-apikey Torznab caps endpoint so it works on Jackett instances locked behind an admin password (where /server/config requires a cookie session). API key is passed via query (not X-Api-Key — Jackett doesn''t honour that header).","descFr":"Nouvelle catégorie de service ''indexer'' avec Jackett en premier membre. Le test de connexion utilise le endpoint Torznab caps (public-with-apikey) pour fonctionner sur des instances Jackett verrouillées par mot de passe admin (où /server/config exige une session cookie). L''API key passe en query (pas en X-Api-Key — Jackett ne reconnaît pas cet en-tête)."},{"type":"feat","titleEn":"Curated icon set expanded","titleFr":"Set d''icônes curated étendu","descEn":"`DynamicIcon` (used by plugin manifests for nav/admin tabs/widgets) gains 8 new icons: Coins, CreditCard, Gift, Crown, Award, Trophy, Gauge, Rocket — to cover subscription/achievements/stats plugin patterns. Unknown icons now log a one-time dev-mode console warning instead of silently falling back to Puzzle, and the available list is documented in docs/plugins.md.","descFr":"`DynamicIcon` (utilisé par les manifests de plugins pour nav/admin tabs/widgets) gagne 8 nouvelles icônes : Coins, CreditCard, Gift, Crown, Award, Trophy, Gauge, Rocket — pour couvrir les patterns subscription/achievements/stats. Les icônes inconnues émettent maintenant un warning console one-time en dev au lieu de fallback silencieusement sur Puzzle, et la liste dispo est documentée dans docs/plugins.md."},{"type":"fix","titleEn":"qBittorrent connection test no longer 403s","titleFr":"Le test de connexion qBittorrent ne renvoie plus 403","descEn":"The qBittorrent provider used to hit `/api/v2/app/version` directly without first authenticating, surfacing a misleading HTTP_FORBIDDEN. It now performs the full `/auth/login` flow, captures the SID cookie, and reports typed errors on bad creds (AUTH_FAILED), IP ban after too many failed attempts (AUTH_BANNED) or missing session cookie (AUTH_NO_SESSION) instead of the bare HTTP code.","descFr":"Le provider qBittorrent tapait `/api/v2/app/version` directement sans s''authentifier d''abord, surfaçant un HTTP_FORBIDDEN trompeur. Il exécute maintenant le flux `/auth/login` complet, capture le cookie SID, et reporte des erreurs typées sur mauvais credentials (AUTH_FAILED), IP temporairement bannie après trop d''essais (AUTH_BANNED) ou cookie de session manquant (AUTH_NO_SESSION) au lieu du code HTTP brut."},{"type":"fix","titleEn":"Admin-only plugins no longer reachable by URL","titleFr":"Les plugins admin-only ne sont plus accessibles par URL","descEn":"Any plugin shipping a `frontend` field was previously mountable at `/p/<id>` whether or not it published a `nav` contribution — admin-only plugins (subscription, qbittorrent-manager…) were therefore reachable by typing the URL even though their data routes were permission-gated. The `/p/<id>` route now refuses to mount any plugin that hasn''t contributed to hookPoint=''nav'', falling back to plugin.not_found.","descFr":"N''importe quel plugin shippant un champ `frontend` était auparavant montable à `/p/<id>` qu''il publie ou non une contribution `nav` — les plugins admin-only (subscription, qbittorrent-manager…) étaient donc atteignables en tapant l''URL même si leurs routes data étaient gated par permissions. La route `/p/<id>` refuse maintenant de monter tout plugin qui n''a pas contribué à hookPoint=''nav'', avec fallback sur plugin.not_found."}]'
) ON CONFLICT ("version") DO NOTHING;
